.frame{overflow:hidden;border:1px solid var(--_line);border-radius:18px;background:var(--_bg);box-shadow:0 12px 32px rgba(15,23,42,.07)}
.inner{display:grid;grid-template-columns:minmax(170px,.8fr) minmax(220px,1.2fr);align-items:center;gap:28px;padding:26px}
.summary{display:flex;align-items:center;gap:16px}
.score-badge{display:flex;width:84px;height:84px;flex:none;align-items:baseline;justify-content:center;padding-top:18px;border-radius:22px;background:var(--_accent);color:#fff;box-shadow:0 12px 24px color-mix(in srgb,var(--_accent) 24%,transparent);font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,'Liberation Mono',monospace;font-size:30px;font-weight:850;font-variant-numeric:tabular-nums}
.score-max{margin-left:2px;font-size:11px;font-weight:750;opacity:.75}
.eyebrow{margin:0 0 5px;color:var(--_accent);font-size:10px;font-weight:800;letter-spacing:.12em;text-transform:uppercase}
h2{margin:0;color:var(--_text);font-size:20px;font-weight:750;letter-spacing:-.02em;line-height:1.2}
.count{margin-top:6px;color:var(--_muted);font-size:12px;font-variant-numeric:tabular-nums}
.visual{min-width:0;padding:18px 20px;border:1px solid var(--_line);border-radius:15px;background:var(--_soft)}
