if(count!==null) copy.appendChild(make('div','count',count.toLocaleString('en-US')+' verified rating'+(count===1?'':'s')));
summary.appendChild(copy); inner.appendChild(summary);
const visual=make('div','visual');
if(mode==='segments'){
  const segments=make('div','segments'); segments.style.setProperty('--segments',String(max)); segments.setAttribute('aria-hidden','true');
  for(let index=0;index<max;index++){ const part=make('div','segment'); const fill=make('span'); fill.style.width=(Math.max(0,Math.min(1,score-index))*100)+'%'; part.appendChild(fill); segments.appendChild(part); }
  visual.appendChild(segments);
}else{
  const stars=make('div','stars'); stars.setAttribute('aria-hidden','true'); const glyph='★'.repeat(max);
  stars.appendChild(make('div','stars-back',glyph)); const fill=make('div','stars-fill',glyph); fill.style.width=(score/max*100)+'%'; stars.appendChild(fill); visual.appendChild(stars);
}
const caption=make('div','caption');
if(data.caption){ caption.textContent=String(data.caption); }else{ caption.appendChild(make('strong','',score.toFixed(1)+' / '+max)); caption.appendChild(document.createTextNode(' overall score')); }
visual.appendChild(caption); inner.appendChild(visual); frame.appendChild(inner); root.appendChild(frame);
parent.appendChild(host);

